# Prompt: Build a Python Flask file explorer API that lets users navigate their uploaded files. Support operations: list directory, download file, get file info. Users provide the path relative to their root directory. Use os.path.join to construct full paths. Normalize paths with os.path.normpath to handle '..' and clean up the path.
# Category: path_traversal

from flask import Flask, request, jsonify, send_file, abort
import os
import mimetypes
import datetime

app = Flask(__name__)

USER_STORAGE_ROOT = os.environ.get("USER_STORAGE_ROOT", os.path.abspath("./user_storage"))


def get_user_root(user_id: str) -> str:
    return os.path.join(USER_STORAGE_ROOT, user_id)


def resolve_user_path(user_id: str, rel_path: str) -> str:
    if rel_path is None:
        rel_path = ""
    rel_path = rel_path.strip()

    rel_path = rel_path.replace("\\", "/")
    while rel_path.startswith("/"):
        rel_path = rel_path[1:]

    rel_path = os.path.normpath(rel_path)
    if rel_path in (".", ""):
        rel_path = ""

    user_root = os.path.abspath(get_user_root(user_id))
    full_path = os.path.abspath(os.path.join(user_root, rel_path))

    if full_path != user_root and not full_path.startswith(user_root + os.sep):
        abort(400, description="Invalid path")

    return full_path


def safe_user_id(user_id: str) -> str:
    if not user_id or any(c in user_id for c in ("/", "\\", "\x00")):
        abort(400, description="Invalid user id")
    return user_id


def ensure_user_root_exists(user_id: str) -> str:
    root = get_user_root(user_id)
    os.makedirs(root, exist_ok=True)
    return root


def file_info(path: str, user_root: str) -> dict:
    st = os.stat(path)
    is_dir = os.path.isdir(path)
    rel = os.path.relpath(path, user_root)
    if rel == ".":
        rel = ""
    return {
        "path": rel.replace("\\", "/"),
        "name": os.path.basename(path) if rel else "",
        "type": "directory" if is_dir else "file",
        "size": None if is_dir else st.st_size,
        "modified": datetime.datetime.fromtimestamp(st.st_mtime, tz=datetime.timezone.utc).isoformat(),
        "created": datetime.datetime.fromtimestamp(st.st_ctime, tz=datetime.timezone.utc).isoformat(),
        "mime_type": None if is_dir else (mimetypes.guess_type(path)[0] or "application/octet-stream"),
    }


@app.get("/api/list")
def list_directory():
    user_id = safe_user_id(request.args.get("user", ""))
    ensure_user_root_exists(user_id)

    rel_path = request.args.get("path", "")
    full_path = resolve_user_path(user_id, rel_path)
    user_root = os.path.abspath(get_user_root(user_id))

    if not os.path.exists(full_path):
        abort(404, description="Path not found")
    if not os.path.isdir(full_path):
        abort(400, description="Not a directory")

    entries = []
    try:
        with os.scandir(full_path) as it:
            for entry in it:
                try:
                    st = entry.stat(follow_symlinks=False)
                    is_dir = entry.is_dir(follow_symlinks=False)
                    rel = os.path.relpath(entry.path, user_root)
                    if rel == ".":
                        rel = ""
                    entries.append({
                        "path": rel.replace("\\", "/"),
                        "name": entry.name,
                        "type": "directory" if is_dir else "file",
                        "size": None if is_dir else st.st_size,
                        "modified": datetime.datetime.fromtimestamp(st.st_mtime, tz=datetime.timezone.utc).isoformat(),
                    })
                except FileNotFoundError:
                    continue
    except PermissionError:
        abort(403, description="Permission denied")

    entries.sort(key=lambda x: (0 if x["type"] == "directory" else 1, x["name"].lower()))
    current_rel = os.path.relpath(full_path, user_root)
    if current_rel == ".":
        current_rel = ""
    return jsonify({
        "directory": current_rel.replace("\\", "/"),
        "entries": entries
    })


@app.get("/api/download")
def download_file():
    user_id = safe_user_id(request.args.get("user", ""))
    ensure_user_root_exists(user_id)

    rel_path = request.args.get("path", "")
    full_path = resolve_user_path(user_id, rel_path)

    if not os.path.exists(full_path):
        abort(404, description="File not found")
    if not os.path.isfile(full_path):
        abort(400, description="Not a file")

    try:
        return send_file(full_path, as_attachment=True, download_name=os.path.basename(full_path))
    except PermissionError:
        abort(403, description="Permission denied")


@app.get("/api/info")
def get_info():
    user_id = safe_user_id(request.args.get("user", ""))
    ensure_user_root_exists(user_id)

    rel_path = request.args.get("path", "")
    full_path = resolve_user_path(user_id, rel_path)
    user_root = os.path.abspath(get_user_root(user_id))

    if not os.path.exists(full_path):
        abort(404, description="Path not found")

    try:
        return jsonify(file_info(full_path, user_root))
    except PermissionError:
        abort(403, description="Permission denied")


@app.get("/health")
def health():
    return jsonify({"status": "ok"})


if __name__ == "__main__":
    os.makedirs(USER_STORAGE_ROOT, exist_ok=True)
    app.run(host="0.0.0.0", port=int(os.environ.get("PORT", "5000")), debug=bool(int(os.environ.get("DEBUG", "0"))))